<template><main class="login"><form @submit.prevent="login"><p class="eyebrow">WOXZA / ADMIN</p><h1>Sign in</h1><p>Use your Woxza staff account to continue.</p><label>Email<input v-model="email" type="email" autocomplete="email" required></label><label>Password<input v-model="password" type="password" autocomplete="current-password" required></label><p v-if="error" class="error">{{ error }}</p><button :disabled="busy">{{ busy?'Signing in…':'Sign in' }}</button></form></main></template>
<script setup>
import { ref } from 'vue'; import { useRoute, useRouter } from 'vue-router';
const email=ref(''),password=ref(''),error=ref(''),busy=ref(false),route=useRoute(),router=useRouter();
async function login(){busy.value=true;error.value='';try{const r=await fetch('/api/admin/login',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({email:email.value,password:password.value})});const body=await r.json();if(!r.ok)throw new Error(body.error||'Unable to sign in');router.replace(typeof route.query.next==='string'?route.query.next:'/admin/debug')}catch(e){error.value=e.message}finally{busy.value=false}}
</script>
<style scoped>.login{min-height:100vh;display:grid;place-items:center;background:#090d18;color:#e7edf8;padding:24px}.login form{width:min(100%,420px);display:grid;gap:16px;padding:34px;border:1px solid #27324a;border-radius:18px;background:#111827;box-shadow:0 24px 80px #0008}.eyebrow{font:700 .75rem ui-monospace,SFMono-Regular,monospace;letter-spacing:.14em;color:#60a5fa}.login h1{font-size:2.3rem;margin:0}.login p{margin:0;color:#9bacbf}.login label{display:grid;gap:7px;font-weight:600}.login input{padding:12px;border:1px solid #34415b;border-radius:8px;background:#0b1220;color:inherit;font:inherit}.login button{border:0;border-radius:8px;padding:12px;background:#3b82f6;color:white;font:700 1rem inherit;cursor:pointer}.error{color:#fda4af!important}</style>
